const EventEmitter = require('events');

class MyEmitter extends EventEmitter {}

const myEmitter = new MyEmitter();

// Listen for 'orderPlaced' event
myEmitter.on('orderPlaced', (order) => {
  console.log(`Order received: ${order.id} for ${order.item}`);
});

// Emit the 'orderPlaced' event
myEmitter.emit('orderPlaced', { id: 1, item: 'Laptop' });

// publisher.js
const EventEmitter = require('events');
const eventEmitter = new EventEmitter();

function placeOrder(order) {
  console.log(`Placing order ${order.id}`);
  eventEmitter.emit('orderPlaced', order);
}

module.exports = { eventEmitter, placeOrder };

