}

const cache = new WeakMap();

function cacheData(obj, data) {
  cache.set(obj, data);
}

// If 'obj' is no longer referenced elsewhere, garbage collector can free it

function getFirstElement(arr: any[]): any {
  return arr[0];
}

const num = getFirstElement([1, 2, 3]); // Type is any
const str = getFirstElement(["a", "b", "c"]); // Type is any

function getFirstElement<T>(arr: T[]): T {
  return arr[0];
}

const num = getFirstElement([1, 2, 3]); // Type is number
const str = getFirstElement(["a", "b", "c"]); // Type is string

interface Box<T> {
  value: T;
}

const numberBox: Box<number> = { value: 123 };
const stringBox: Box<string> = { value: "hello" };

class Stack<T> {
  private items: T[] = [];

  push(item: T) {
    this.items.push(item);
  }

  pop(): T | undefined {
    return this.items.pop();
  }
}

const numberStack = new Stack<number>();
numberStack.push(10);
const poppedNumber = numberStack.pop(); // number | undefined

const stringStack = new Stack<string>();
stringStack.push("hello");
const poppedString = stringStack.pop(); // string | undefined

function formatValue(value: string | number) {
  if (typeof value === 'string') {
    // Here TypeScript knows `value` is a string
    return value.trim().toUpperCase();
  } else {
    // Here TypeScript knows `value` is a number
    return value.toFixed(2);
  }
}

class Dog {
  bark() { return 'Woof!'; }
}
class Cat {
  meow() { return 'Meow!'; }
}

function speak(animal: Dog | Cat) {
  if (animal instanceof Dog) {
    return animal.bark();
  } else {
    return animal.meow();
  }
}

interface Fish { swim: () => void; }
interface Bird { fly: () => void; }

function isFish(pet: Fish | Bird): pet is Fish {
  return (pet as Fish).swim !== undefined;
}

function move(pet: Fish | Bird) {
  if (isFish(pet)) {
    pet.swim();
  } else {
    pet.fly();
  }
}

